mapper.select:
select org_id, org_name, org_code, contact_name, contact_phone, address, status, package_type, expire_time,
       del_flag, remark, create_by, create_time, update_by, update_time
from mem_organization
where del_flag = '0'

    and org_name like concat('%', #{orgName}, '%')


    and org_code = #{orgCode}


    and status = #{status}


    and package_type = #{packageType}

order by create_time desc
